import React from 'react';
import './CropHealth.css';

function CropHealth() {
  return (
    <div className="crop-health">
      <h1>Crop Health Monitoring</h1>
      <p>Log crop health data and detect potential issues.</p>
    </div>
  );
}

export default CropHealth;
